package com.thoughtworks.go.domain;

import com.thoughtworks.go.util.json.JsonAware;

import java.io.Serializable;
import java.util.LinkedHashMap;
import java.util.Map;
import java.util.Objects;

public class Property implements JsonAware, Serializable {
    private String key;
    private String value;

    public Property() {
    }

    public Property(String key, String value) {
        this.key = key;
        this.value = value;
    }

    public String getKey() {
        return key;
    }

    public String getValue() {
        return value;
    }

    void setValue(String value) {
        this.value = value;
    }


    public String toString() {
        return "Name=" + key + " Value=" + value;
    }

    public boolean equals(Object that) {
        if (this == that) {
            return true;
        }
        if (that == null) {
            return false;
        }
        if (this.getClass() != that.getClass()) {
            return false;
        }

        return equals((Property) that);
    }

    private boolean equals(Property that) {
        if (!Objects.equals(this.key, that.key)) {
            return false;
        }
        if (!Objects.equals(this.value, that.value)) {
            return false;
        }
        return true;
    }

    public int hashCode() {
        int result;
        result = key.hashCode();
        result = 31 * result + value.hashCode();
        return result;
    }

    public Map<String, Object> toJson() {
        Map<String, Object> jsonMap = new LinkedHashMap<>();
        jsonMap.put(key, value);
        return jsonMap;
    }
}
